        WBVappProgressViewController *progressVC = [[WBVappProgressViewController alloc] initWithVApp:vapp];
        progressVC.progressView.titleLabel.text = @"正在更新应用资源";
        progressVC.progressView.subTitleLabel.text = @"请保持网络连接通畅，不要退出";
        progressVC.progressView.tipIndex = [self getCurrentLaunchTipIndex];
        progressVC.progressView.tips = [self getCurrentLaunchTips];
        self.launchVC = (WBVappLaunchViewController *)progressVC;

        UIViewController *rootVc = [WBAppManager getUIApplicationRootViewController];
        [rootVc presentViewController:self.launchVC animated:NO completion:^{
            [[WBVAppManager sharedManager] waitUntilResourceDownloadedForVApp:vapp callback:^{
                if (handler) handler(vapp.status == WBVappStatusResourceDownloaded);
            }];
        }];
    };
    if (_launchVC) {
        [_launchVC dismissViewControllerAnimated:NO completion:^{
            waitBlock();
        }];
    } else {
        waitBlock();
    }
}

- (void)waitVAppResourceInstall:(WBVAppModel *)vapp completion:(void (^)(BOOL success))handler {
