        self.launchVC = (WBVappLaunchViewController *)progressVC;

        UIViewController *rootVc = [WBAppManager getUIApplicationRootViewController];
        [rootVc presentViewController:self.launchVC animated:NO completion:^{
            if (vapp.status == WBVappStatusResourceInstalled) {
                if (handler) handler(YES);
                return;
            }
            [[WBVAppManager sharedManager] waitUntilResourceInstalledForVApp:vapp callback:^{
                if (handler) handler(vapp.status == WBVappStatusResourceInstalled);
            }];
        }];
    };
    if (_launchVC) {
        [_launchVC dismissViewControllerAnimated:NO completion:^{
            waitBlock();
        }];
    } else {
        waitBlock();
    }
}

